// ── Validate payload ────────────────────────────────────────────────────
const body = $input.first().json.body ?? $input.first().json;

const { startup_id, metric_id, value } = body;

// Required field checks
if (!startup_id) {
  return [{ json: { __error: true, status: 400, message: 'Missing required field: startup_id' } }];
}
if (!metric_id) {
  return [{ json: { __error: true, status: 400, message: 'Missing required field: metric_id' } }];
}
if (value === undefined || value === null || value === '') {
  return [{ json: { __error: true, status: 400, message: 'Missing required field: value' } }];
}

// UUID format check
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRe.test(startup_id)) {
  return [{ json: { __error: true, status: 400, message: 'startup_id must be a valid UUID' } }];
}
if (!uuidRe.test(metric_id)) {
  return [{ json: { __error: true, status: 400, message: 'metric_id must be a valid UUID' } }];
}

return [{ json: { startup_id, metric_id, value: String(value), __error: false } }];

// ── Validate value against metric config ─────────────────────────────────
const payload = $('Validate Payload').first().json;
const metricResponse = $input.first().json;

if ($input.first().json.error || !metricResponse.metric) {
  return [{ json: { __error: true, status: 400, message: `Metric ${payload.metric_id} not found` } }];
}

const metric = metricResponse.metric;
const value = payload.value;

// Type-specific validation
if (metric.type === 'numeric') {
  const num = parseFloat(value);
  if (isNaN(num)) {
    return [{ json: { __error: true, status: 400, message: `Metric '${metric.name}' requires a numeric value, got: ${value}` } }];
  }
  if (metric.valid_min !== null && num < metric.valid_min) {
    return [{ json: { __error: true, status: 400, message: `Value ${num} is below minimum ${metric.valid_min} for metric '${metric.name}'` } }];
  }
  if (metric.valid_max !== null && num > metric.valid_max) {
    return [{ json: { __error: true, status: 400, message: `Value ${num} exceeds maximum ${metric.valid_max} for metric '${metric.name}'` } }];
  }
}

// Compute score (normalize value to 0-10)
// For numeric: linear interpolation between valid_min and valid_max → 0-10
// For document/qualitative: score comes from the caller (defaulting to 5 pending LLM)
let score = 5; // default for document/qualitative

if (metric.type === 'numeric') {
  const num = parseFloat(value);
  if (metric.valid_min !== null && metric.valid_max !== null && metric.valid_max > metric.valid_min) {
    score = Math.round(((num - metric.valid_min) / (metric.valid_max - metric.valid_min)) * 10 * 100) / 100;
    score = Math.min(Math.max(score, 0), 10);
  } else {
    // No defined range: score provided by caller or default to 5
    score = typeof payload.score === 'number' ? payload.score : 5;
  }
}

if (typeof payload.score === 'number') {
  // Caller explicitly provided a score — trust it (e.g. for qualitative self-assessment)
  score = Math.min(Math.max(payload.score, 0), 10);
}

return [{ json: {
  startup_id: payload.startup_id,
  metric_id:  payload.metric_id,
  value:      value,
  score:      score,
  confidence_tag: 'self_reported',
  __error: false,
  metric_name: metric.name,
} }];
